questionvariables.text:
/* ===== Randomised parameters ===== */
N_val:  rand([200, 500, 1000]);
lc_val: rand([0.2, 0.3, 0.4]);
lg_val: rand([5e-4, 1e-3, 2e-3]);
Ac_val: rand([4e-4, 9e-4, 16e-4]);
mur_val: rand([500, 1000, 2000]);
mu0: 4*%pi*1e-7;

/* ===== Reluctances (symbolic and numerical) ===== */
ta_Rc_sym: lc_val/(mur_val*mu0*Ac_val);
ta_Rg_sym: lg_val/(mu0*Ac_val);
ta_Rc: float(ta_Rc_sym);
ta_Rg: float(ta_Rg_sym);
ta_Rt: float(ta_Rc + ta_Rg);

/* ===== Inductance ===== */
ta_L: float(N_val^2 / ta_Rt);

/* ===== Sensitivity: dL/dlg ===== */
/* L = N^2 / (lc/(mur*mu0*Ac) + lg/(mu0*Ac))                        */
/* Let D = lc/(mur*mu0*Ac) + lg/(mu0*Ac). Then L = N^2/D.            */
/* dD/dlg = 1/(mu0*Ac). dL/dlg = -N^2/D^2 * (1/(mu0*Ac))            */
/* = -N^2*mu0*Ac / (lc/mur + lg)^2                                    */
ta_dLdlg_sym: -N_val^2*mu0*Ac_val / (lc_val/mur_val + lg_val)^2;
ta_dLdlg: float(ta_dLdlg_sym);

/* ===== Percentage change for 10% increase in lg ===== */
delta_lg: 0.1*lg_val;
ta_pct: float(ta_dLdlg * delta_lg / ta_L * 100);

/* ===== MCQ answers ===== */
ta_analogy: 1;
ta_dominator: if ta_Rg > ta_Rc then 1 else 2;
ta_design_reason: 1;

/* ===== Teacher answers for each input ===== */
ta1: ta_analogy;
ta2: ta_Rc_sym;
ta3: ta_Rg_sym;
ta4: ta_Rt;
ta5: ta_L;
ta6: ta_dLdlg_sym;
ta7: ta_pct;
ta8: ta_design_reason;
